import React, { Suspense, lazy } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Layout from './components/Layout/Layout';
import Spinner from './components/common/Spinner';

// Lazy-loaded pages
const LandingPage    = lazy(() => import('./pages/Landing/LandingPage'));
const LoginPage      = lazy(() => import('./pages/Login/LoginPage'));
const DashboardPage  = lazy(() => import('./pages/Dashboard/DashboardPage'));
const AttendancePage = lazy(() => import('./pages/Attendance/AttendancePage'));
const LeavePage      = lazy(() => import('./pages/Leave/LeavePage'));
const SalaryPage     = lazy(() => import('./pages/Salary/SalaryPage'));
const EmployeesPage  = lazy(() => import('./pages/Employees/EmployeesPage'));
const ShiftsPage     = lazy(() => import('./pages/Shifts/ShiftsPage'));
const ReportsPage    = lazy(() => import('./pages/Reports/ReportsPage'));
const ProfilePage    = lazy(() => import('./pages/Profile/ProfilePage'));

// ── Guards ──────────────────────────────────────────────────────────────────
const PrivateRoute = ({ children }) => {
  const { isAuthenticated, loading } = useAuth();
  if (loading) return <Spinner fullscreen />;
  return isAuthenticated ? children : <Navigate to="/login" replace />;
};

const AdminRoute = ({ children }) => {
  const { isAdminOrManager, loading } = useAuth();
  if (loading) return <Spinner fullscreen />;
  return isAdminOrManager ? children : <Navigate to="/dashboard" replace />;
};

const PublicRoute = ({ children }) => {
  const { isAuthenticated, loading } = useAuth();
  if (loading) return <Spinner fullscreen />;
  return isAuthenticated ? <Navigate to="/dashboard" replace /> : children;
};

// ── App Shell ────────────────────────────────────────────────────────────────
const AppRoutes = () => (
  <Suspense fallback={<Spinner fullscreen />}>
    <Routes>
      <Route path="/" element={<PublicRoute><LandingPage /></PublicRoute>} />
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />

      <Route element={<PrivateRoute><Layout /></PrivateRoute>}>
        <Route index                element={<Navigate to="/dashboard" replace />} />
        <Route path="dashboard"     element={<DashboardPage />} />
        <Route path="attendance"    element={<AttendancePage />} />
        <Route path="leaves"        element={<LeavePage />} />
        <Route path="salary"        element={<SalaryPage />} />
        <Route path="profile"       element={<ProfilePage />} />

        {/* Admin / Manager only */}
        <Route path="employees"     element={<AdminRoute><EmployeesPage /></AdminRoute>} />
        <Route path="shifts"        element={<AdminRoute><ShiftsPage /></AdminRoute>} />
        <Route path="reports"       element={<AdminRoute><ReportsPage /></AdminRoute>} />
      </Route>

      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  </Suspense>
);

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
}
